// src/app/layout.tsx
"use client"; // Transforma o layout em um ambiente dinâmico e interativo

import { useState, useEffect } from "react";
import { Roboto } from "next/font/google";
import { 
  Home, Lock, MessageSquare, Gamepad2, Settings, 
  LogOut, ChevronLeft, ChevronRight, Fingerprint
} from "lucide-react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import "./globals.css";

// Configuração da fonte Roboto otimizada
const roboto = Roboto({ 
  weight: ['300', '400', '500', '700'],
  subsets: ['latin'],
  variable: '--font-roboto',
});

export default function RootLayout({ children }: { children: React.ReactNode }) {
  // Estado para controlar se a barra lateral está expandida ou retraída
  const [isCollapsed, setIsCollapsed] = useState(false);
  const [isInitializing, setIsInitializing] = useState(true);
  const pathname = usePathname();

  // Efeito de "Blindagem/Carregamento" inspirado na referência Orion
  useEffect(() => {
    const timer = setTimeout(() => {
      setIsInitializing(false);
    }, 1500);
    return () => clearTimeout(timer);
  }, []);

  // TELA DE INICIALIZAÇÃO DE LUXO (Imersão da Marca)
  if (isInitializing) {
    return (
      <html lang="pt-BR">
        <body className="bg-[#1c1a19] min-h-screen flex items-center justify-center flex-col relative overflow-hidden">
          {/* Brilho radial de fundo */}
          <div className="absolute w-[500px] h-[500px] bg-atelier-terracota/10 blur-[150px] rounded-full"></div>
          
          <div className="relative flex items-center justify-center z-10">
            <div className="absolute w-16 h-16 border border-atelier-terracota/30 rounded-full animate-ping"></div>
            <div className="w-12 h-12 border-2 border-atelier-terracota border-t-transparent rounded-full animate-spin relative z-10"></div>
            <div className="absolute w-6 h-6 bg-atelier-terracota/20 rounded-full blur-md animate-pulse"></div>
          </div>
          <p className="mt-8 font-roboto text-[0.65rem] text-atelier-terracota tracking-[0.4em] uppercase font-bold animate-pulse">
            Sincronizando Cofre Atelier...
          </p>
        </body>
      </html>
    );
  }

  return (
    <html lang="pt-BR" className={`${roboto.variable}`}>
      <body className="font-sans antialiased text-atelier-creme h-screen overflow-hidden flex transition-colors duration-300">
        
        {/* ==========================================
            SIDEBAR RETRÁTIL (GLASS PANEL PREMIUM)
            ========================================== */}
        <aside 
          className={`${isCollapsed ? 'w-24' : 'w-72'} bg-[#141211]/80 backdrop-blur-xl border-r border-white/5 flex flex-col justify-between relative z-50 transition-all duration-500 ease-in-out shrink-0 shadow-[10px_0_30px_rgba(0,0,0,0.5)]`}
        >
          {/* BOTÃO DE RETRAIR/EXPANDIR (Flutuante na borda) */}
          <button 
            onClick={() => setIsCollapsed(!isCollapsed)}
            className="absolute -right-3.5 top-10 bg-[#1c1a19] border border-atelier-terracota/50 text-atelier-terracota rounded-full p-1.5 hover:bg-atelier-terracota hover:text-[#1c1a19] transition-all z-50 shadow-[0_0_15px_rgba(173,111,64,0.3)]"
          >
            {isCollapsed ? <ChevronRight size={14} /> : <ChevronLeft size={14} />}
          </button>

          {/* TOPO: LOGO DO ATELIER */}
          <div className={`p-8 flex ${isCollapsed ? 'justify-center' : 'justify-start'} border-b border-white/5 transition-all duration-500 overflow-hidden h-28 items-center relative`}>
             {/* Luz sutil atrás da logo */}
             <div className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 w-12 h-12 bg-atelier-rose/10 blur-xl rounded-full pointer-events-none"></div>
             
             {isCollapsed ? (
                <div className="w-12 h-12 flex items-center justify-center hover:scale-105 transition-transform drop-shadow-lg relative z-10 cursor-pointer">
                  <img src="/images/Símbolo Rosa.png" alt="Atelier" className="w-full h-full object-contain" />
                </div>
             ) : (
                <div className="flex items-center gap-4 relative z-10 cursor-pointer">
                  <div className="w-10 h-10 shrink-0 drop-shadow-lg">
                    <img src="/images/Símbolo Rosa.png" alt="Atelier" className="w-full h-full object-contain" />
                  </div>
                  <div className="flex flex-col">
                    <span className="font-elegant text-2xl text-atelier-creme tracking-wider leading-none">Atelier</span>
                    <span className="font-roboto text-[0.55rem] uppercase tracking-[0.3em] text-atelier-terracota font-bold mt-1">Portal Exclusivo</span>
                  </div>
                </div>
             )}
          </div>

          {/* NAVEGAÇÃO PRINCIPAL (Micro-Tipografia & Efeitos Glow) */}
          <nav className="flex-1 py-8 px-4 space-y-2 overflow-y-auto custom-scrollbar">
            {!isCollapsed && (
              <p className="text-[0.6rem] text-atelier-grafite uppercase tracking-[0.25em] mb-6 px-3 font-bold">
                Painel de Controle
              </p>
            )}
            
            <NavItem href="/" icon={<Home size={20} strokeWidth={1.5} />} label="Home (Visão Geral)" collapsed={isCollapsed} active={pathname === "/"} />
            <NavItem href="/cofre" icon={<Lock size={20} strokeWidth={1.5} />} label="O Cofre" collapsed={isCollapsed} active={pathname === "/cofre"} />
            <NavItem href="/canais" icon={<MessageSquare size={20} strokeWidth={1.5} />} label="Canais & Avisos" collapsed={isCollapsed} active={pathname === "/canais"} />
            <NavItem href="/referencias" icon={<Fingerprint size={20} strokeWidth={1.5} />} label="Referências" collapsed={isCollapsed} active={pathname === "/referencias"} />
            <NavItem href="/gamificacao" icon={<Gamepad2 size={20} strokeWidth={1.5} />} label="Conquistas" collapsed={isCollapsed} active={pathname === "/gamificacao"} />
          </nav>

          {/* RODAPÉ: PERFIL E LOGOUT */}
          <div className="p-4 border-t border-white/5 space-y-2 bg-black/20">
            <NavItem href="/configuracoes" icon={<Settings size={20} strokeWidth={1.5} />} label="Configurações" collapsed={isCollapsed} active={pathname === "/configuracoes"} />
            
            <button className={`w-full flex items-center ${isCollapsed ? 'justify-center' : 'justify-start'} gap-4 px-3 py-3 text-atelier-grafite hover:text-red-400 hover:bg-red-500/10 rounded-xl transition-all duration-300 font-roboto text-sm group mt-2 border border-transparent hover:border-red-500/20`}>
              <LogOut size={20} strokeWidth={1.5} className="group-hover:-translate-x-1 transition-transform" />
              {!isCollapsed && <span className="font-bold tracking-wide text-xs uppercase">Desconectar</span>}
            </button>
          </div>
        </aside>

        {/* ==========================================
            ÁREA CENTRAL DE CONTEÚDO (O PALCO)
            ========================================== */}
        <main className="flex-1 relative overflow-y-auto transition-colors duration-300 custom-scrollbar">
          {/* Brilhos Radiais de Fundo (A Assinatura Visual do Orion) */}
          <div className="fixed top-[-10%] right-[-5%] w-[600px] h-[600px] bg-atelier-terracota/10 blur-[200px] rounded-full pointer-events-none z-0"></div>
          <div className="fixed bottom-[-10%] left-[20%] w-[400px] h-[400px] bg-atelier-rose/5 blur-[150px] rounded-full pointer-events-none z-0"></div>
          
          <div className="p-8 md:p-12 w-full max-w-[1600px] mx-auto relative z-10 min-h-full">
            {children}
          </div>
        </main>

      </body>
    </html>
  );
}

// ==========================================
// COMPONENTE DE NAVEGAÇÃO DE ELITE
// ==========================================
function NavItem({ href, icon, label, collapsed, active }: { href: string, icon: React.ReactNode, label: string, collapsed: boolean, active: boolean }) {
  return (
    <Link 
      href={href} 
      title={collapsed ? label : ""}
      className={`flex items-center ${collapsed ? 'justify-center' : 'justify-start'} gap-4 px-4 py-3.5 rounded-xl font-roboto text-sm transition-all duration-300 group relative overflow-hidden ${
        active 
          ? "bg-atelier-terracota/10 text-atelier-terracota border border-atelier-terracota/20 shadow-[inset_4px_0_15px_rgba(173,111,64,0.1)]" 
          : "text-atelier-grafite hover:text-atelier-creme hover:bg-white/5 border border-transparent"
      }`}
    >
      {/* Luz indicadora lateral para o item ativo */}
      {active && <div className="absolute left-0 top-0 bottom-0 w-1 bg-atelier-terracota shadow-[0_0_10px_#ad6f40]"></div>}
      
      <span className={`${active ? "scale-105" : "group-hover:scale-110 transition-transform"}`}>
        {icon}
      </span>
      
      {!collapsed && (
        <span className="font-bold tracking-wider text-[0.7rem] uppercase whitespace-nowrap z-10">
          {label}
        </span>
      )}
    </Link>
  );
}